content:
{
  "sentences": [
    {
      "text": "我想退貨，因為這個尺寸不合。",
      "pinyin": "Wǒ xiǎng tuìhuò, yīnwèi zhège chǐcùn bù hé.",
      "pinyin_numeric": "wo3 xiang3 tui4huo4, yin1wei4 zhe4ge chi3cun4 bu4 he2.",
      "translation_en": "I want to return this because the size doesn't fit.",
      "translation_ko": "이 사이즈가 맞지 않아서 환불하고 싶습니다."
    },
    {
      "text": "我要換貨，因為顏色不對。",
      "pinyin": "Wǒ yào huànhuò, yīnwèi yánsè bù duì.",
      "pinyin_numeric": "wo3 yao4 huan4huo4, yin1wei4 yan2se4 bu4 dui4.",
      "translation_en": "I want to exchange this because the color is wrong.",
      "translation_ko": "색상이 달라서 교환하고 싶습니다."
    },
    {
      "text": "這個商品有瑕疵，我想退錢。",
      "pinyin": "Zhège shāngpǐn yǒu xiácī, wǒ xiǎng tuì qián.",
      "pinyin_numeric": "zhe4ge shang1pin3 you3 xia2ci1, wo3 xiang3 tui4 qian2.",
      "translation_en": "This product has a defect; I want a refund.",
      "translation_ko": "이 제품에 하자가 있어서 환불받고 싶습니다."
    },
    {
      "text": "我買的杯子破掉了，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de bēizi pò diào le, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de bei1zi po4 diao4 le, ke3yi3 tui4huo4 ma0?",
      "translation_en": "The cup I bought is broken; can I return it?",
      "translation_ko": "제가 산 컵이 깨졌는데 환불할 수 있나요?"
    },
    {
      "text": "這件衣服髒掉了，我要換一件新的。",
      "pinyin": "Zhè jiàn yīfu zāng diào le, wǒ yào huàn yī jiàn xīn de.",
      "pinyin_numeric": "zhe4 jian4 yi1fu zang1 diao4 le, wo3 yao4 huan4 yi1 jian4 xin1 de.",
      "translation_en": "This piece of clothing is dirty; I want to exchange it for a new one.",
      "translation_ko": "이 옷이 더러워졌는데 새것으로 교환하고 싶습니다."
    },
    {
      "text": "我沒有發票，還可以退貨嗎？",
      "pinyin": "Wǒ méiyǒu fāpiào, hái kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mei2you3 fa1piao4, hai2 ke3yi3 tui4huo4 ma0?",
      "translation_en": "I don't have the receipt; can I still return it?",
      "translation_ko": "영수증이 없는데도 환불할 수 있나요?"
    },
    {
      "text": "超過七天就不能退貨了。",
      "pinyin": "Chāoguò qī tiān jiù bù néng tuìhuò le.",
      "pinyin_numeric": "chao1guo4 qi1 tian1 jiu4 bu4 neng2 tui4huo4 le.",
      "translation_en": "After seven days, you can't return it anymore.",
      "translation_ko": "7일이 지나면 환불할 수 없습니다."
    },
    {
      "text": "我要退貨，請幫我填寫退貨單。",
      "pinyin": "Wǒ yào tuìhuò, qǐng bāng wǒ tiánxiě tuìhuò dān.",
      "pinyin_numeric": "wo3 yao4 tui4huo4, qing3 bang1 wo3 tian2xie3 tui4huo4 dan1.",
      "translation_en": "I want to return this; please help me fill out the return form.",
      "translation_ko": "환불하고 싶은데 환불 신청서를 작성하는 것을 도와주세요."
    },
    {
      "text": "這個包裝已經拆開了，不能換貨。",
      "pinyin": "Zhège bāozhuāng yǐjīng chāi kāi le, bù néng huànhuò.",
      "pinyin_numeric": "zhe4ge bao1zhuang1 yi3jing1 chai1 kai1 le, bu4 neng2 huan4huo4.",
      "translation_en": "The packaging has already been opened; you can't exchange it.",
      "translation_ko": "포장이 이미 개봉되어서 교환할 수 없습니다."
    },
    {
      "text": "我想換貨，可是要補差價嗎？",
      "pinyin": "Wǒ xiǎng huànhuò, kěshì yào bǔ chājià ma?",
      "pinyin_numeric": "wo3 xiang3 huan4huo4, ke3shi4 yao4 bu3 cha1jia4 ma0?",
      "translation_en": "I want to exchange it, but do I need to pay the price difference?",
      "translation_ko": "교환하고 싶은데 차액을 지불해야 하나요?"
    }
  ]
}
